## ----compare-tab--------------------------------------------------------------
compare_tab <- data.frame(
  Method = c("Split conformal", "CV+", "Jackknife+"),
  Target = c(0.90, 0.90, 0.90),
  `Empirical coverage` = c(0.925, 0.907, 0.905),
  `Mean width` = c(4.340, 4.016, 4.027),
  check.names = FALSE
)
knitr::kable(
  compare_tab,
  caption = "Empirical coverage and mean interval width across three regression methods on a common sample. Synthetic data with 500 training points, 400 test points, and Gaussian noise with unit standard deviation. Target coverage 0.90. The CV+ variant is fit with ten folds; Jackknife+ is leave-one-out. All three methods reach target coverage; the cross-validated variants achieve meaningfully tighter intervals.",
  label = "compare",
  booktabs = TRUE,
  align = "lrrr"
)


## ----compare, fig.cap = "Mean prediction-interval width across split, CV+, and Jackknife+ on a common regression task. Bars show mean width; text above each bar reports empirical coverage on a 400-point held-out test set. Target coverage is 0.90. CV+ and Jackknife+ recover roughly 9 per cent width relative to split conformal by using all training data for both fitting and calibration.", fig.alt = "A bar chart with three bars, one each for split conformal, CV+, and Jackknife+. The split conformal bar is the tallest at about 4.34 units of mean interval width; the CV+ and Jackknife+ bars are nearly identical and about 9 per cent shorter, at around 4.02 units. Each bar has its empirical coverage labelled above it: 0.925 for split, 0.907 for CV+, and 0.905 for Jackknife+."----
knitr::include_graphics("figures/fig2_compare.pdf")


## ----aps, fig.cap = "Mean APS prediction-set size grouped by predictive entropy decile, three-class synthetic task, target coverage 0.90. Training set of 600 observations with three classes separable up to an overlap region around the decision boundary; 300 test points scored by \\texttt{conformal\\_aps()} wrapping a 200-tree \\texttt{ranger} classifier. Difficulty deciles are computed from the entropy of the classifier softmax output. Mean set size rises monotonically with entropy, from near one in the easy deciles to near three at the decision boundary.", fig.alt = "A bar chart with ten bars, one per entropy decile. Mean prediction-set size starts at just above one for the lowest-entropy decile, rises gradually across the middle deciles, and reaches close to three for the highest-entropy decile. The monotonic rise shows APS producing larger sets for harder, higher-entropy test points."----
knitr::include_graphics("figures/fig3_aps_sets.pdf")


